import{_ as t,a,b as r,c as d,d as o,e as n,f as l}from"./chunks/添加dc新渠道配置.jxAOeu6M.js";import{_ as i,o as s,c,a2 as h}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"افزودن Discord Channel","description":"","frontmatter":{},"headers":[],"relativePath":"fa/upload/discord.md","filePath":"fa/upload/discord.md","lastUpdated":1781962217000}'),p={name:"fa/upload/discord.md"};function b(m,e,u,g,D,v){return s(),c("div",null,[...e[0]||(e[0]=[h('<h1 id="افزودن-discord-channel" tabindex="-1">افزودن Discord Channel <a class="header-anchor" href="#افزودن-discord-channel" aria-label="Permalink to &quot;افزودن Discord Channel&quot;">​</a></h1><h2 id="پیش-از-شروع-چه-چیزهایی-لازم-است" tabindex="-1">پیش از شروع چه چیزهایی لازم است <a class="header-anchor" href="#پیش-از-شروع-چه-چیزهایی-لازم-است" aria-label="Permalink to &quot;پیش از شروع چه چیزهایی لازم است&quot;">​</a></h2><table tabindex="0"><thead><tr><th>مورد</th><th>کاربرد</th></tr></thead><tbody><tr><td>Discord account</td><td>برای ساخت server، channel و developer application.</td></tr><tr><td>Discord server</td><td>bot قبل از دسترسی به channel باید عضو server باشد.</td></tr><tr><td>Text channel</td><td>images و files به این channel ارسال می‌شوند.</td></tr><tr><td>Discord Developer Portal</td><td>برای ساخت application، ساخت bot و گرفتن <code>Bot Token</code>.</td></tr></tbody></table><h2 id="کجا-اضافه-کنیم" tabindex="-1">کجا اضافه کنیم <a class="header-anchor" href="#کجا-اضافه-کنیم" aria-label="Permalink to &quot;کجا اضافه کنیم&quot;">​</a></h2><ol><li>System Settings را باز کنید.</li><li>وارد Upload Settings شوید.</li><li>از گوشه بالا سمت راست Add Channel را بزنید.</li><li><code>Discord</code> را انتخاب کنید.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>کاربرد</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>نام قابل‌تشخیص برای این channel، مثل <code>Discord Primary</code>.</td><td>Required</td></tr><tr><td>Bot Token</td><td>Discord bot token.</td><td>Required</td></tr><tr><td>Channel ID</td><td>ID مربوط به target text channel.</td><td>Required</td></tr><tr><td>Proxy URL (optional)</td><td>فقط اگر Discord CDN access ناپایدار است. URL کامل را همراه <code>https://</code> وارد کنید.</td><td>Optional</td></tr></tbody></table><h2 id="مراحل-setup" tabindex="-1">مراحل setup <a class="header-anchor" href="#مراحل-setup" aria-label="Permalink to &quot;مراحل setup&quot;">​</a></h2><h3 id="_1-ساخت-discord-server-و-text-channel" tabindex="-1">1. ساخت Discord Server و Text Channel <a class="header-anchor" href="#_1-ساخت-discord-server-و-text-channel" aria-label="Permalink to &quot;1. ساخت Discord Server و Text Channel&quot;">​</a></h3><ol><li>Discord را باز کنید.</li><li>server جدید بسازید، یا از server موجودی که مالک آن هستید استفاده کنید.</li><li>در همان server یک text channel بسازید.</li></ol><p><img src="'+t+'" alt="Create a server" loading="lazy"></p><h3 id="_2-ساخت-bot-در-discord-developer-portal" tabindex="-1">2. ساخت Bot در Discord Developer Portal <a class="header-anchor" href="#_2-ساخت-bot-در-discord-developer-portal" aria-label="Permalink to &quot;2. ساخت Bot در Discord Developer Portal&quot;">​</a></h3><ol><li>Discord Developer Portal را باز کنید: <code>https://discord.com/developers/applications</code></li><li><code>New Application</code> را بزنید.</li><li>application name را وارد و create کنید.</li><li>از left sidebar صفحه <code>Bot</code> را باز کنید.</li><li>در صفحه <code>Bot</code>، token را generate یا reset کنید.</li><li>token را ذخیره کنید.</li></ol><p>این مقدار همان <code>Bot Token</code> است که باید در ImgBed وارد کنید.</p><p><img src="'+a+'" alt="View the bot token" loading="lazy"></p><h3 id="_3-ساخت-oauth2-invite-link-و-نصب-bot" tabindex="-1">3. ساخت OAuth2 Invite Link و نصب Bot <a class="header-anchor" href="#_3-ساخت-oauth2-invite-link-و-نصب-bot" aria-label="Permalink to &quot;3. ساخت OAuth2 Invite Link و نصب Bot&quot;">​</a></h3><ol><li>از left sidebar صفحه <code>OAuth2</code> را باز کنید.</li><li>زیر scopes، <code>bot</code> را انتخاب کنید.</li><li>در permission area این permissions را enable کنید:</li></ol><table tabindex="0"><thead><tr><th>Permission</th><th>Required</th></tr></thead><tbody><tr><td>View Channels</td><td>Yes</td></tr><tr><td>Send Messages</td><td>Yes</td></tr><tr><td>Attach Files</td><td>Yes</td></tr><tr><td>Read Message History</td><td>Yes</td></tr></tbody></table><ol start="4"><li>پایین صفحه confirm کنید integration type برابر <code>Guild Install</code> باشد.</li><li>generated URL را copy کنید.</li><li>آن URL را در browser باز کنید.</li><li>target server را انتخاب کنید.</li><li>authorization flow را کامل کنید.</li></ol><p><img src="'+r+'" alt="Select bot permissions in OAuth2" loading="lazy"></p><p><img src="'+d+'" alt="Invite the bot to the channel" loading="lazy"></p><h3 id="_4-enable-کردن-developer-mode-و-copy-کردن-channel-id" tabindex="-1">4. Enable کردن Developer Mode و Copy کردن Channel ID <a class="header-anchor" href="#_4-enable-کردن-developer-mode-و-copy-کردن-channel-id" aria-label="Permalink to &quot;4. Enable کردن Developer Mode و Copy کردن Channel ID&quot;">​</a></h3><ol><li>در Discord، پایین سمت چپ کنار avatar روی gear icon بزنید.</li><li>از left sidebar بخش Advanced را باز کنید.</li><li>Developer Mode را enable کنید.</li><li>به target text channel برگردید.</li><li>روی channel name راست‌کلیک کنید.</li><li>Copy Channel ID را بزنید.</li></ol><p>عدد copy‌شده همان <code>Channel ID</code> موردنیاز ImgBed است.</p><p><img src="'+o+'" alt="Enable developer mode" loading="lazy"></p><p><img src="'+n+'" alt="Copy the channel ID" loading="lazy"></p><h3 id="_5-پر-کردن-discord-channel-در-imgbed" tabindex="-1">5. پر کردن Discord Channel در ImgBed <a class="header-anchor" href="#_5-پر-کردن-discord-channel-در-imgbed" aria-label="Permalink to &quot;5. پر کردن Discord Channel در ImgBed&quot;">​</a></h3><p>به channel configuration dialog برگردید و fields را این‌گونه پر کنید:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Channel name</td><td>custom channel name، مثل <code>DiscordPrimary</code>.</td></tr><tr><td>Bot Token</td><td>token ذخیره‌شده از صفحه <code>Bot</code> در Discord Developer Portal.</td></tr><tr><td>Channel ID</td><td>channel ID کپی‌شده از Discord.</td></tr><tr><td>Proxy URL (optional)</td><td>فقط در صورت نیاز، مثل <code>https://your-proxy.example.com</code>.</td></tr></tbody></table><p>در پایان Save را بزنید.</p><p><img src="'+l+`" alt="Add the Discord channel configuration" loading="lazy"></p><h2 id="روش-بررسی" tabindex="-1">روش بررسی <a class="header-anchor" href="#روش-بررسی" aria-label="Permalink to &quot;روش بررسی&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>روش بررسی</th></tr></thead><tbody><tr><td>Channel card appears</td><td>پس از Save، صفحه Upload Settings باید Discord channel card را نشان دهد.</td></tr><tr><td>Channel can be enabled</td><td>Active switch باید روشن بماند.</td></tr><tr><td>Configuration is saved</td><td>detail view باید نشان دهد Bot Token و Channel ID ذخیره شده‌اند.</td></tr><tr><td>Upload works</td><td>یک test image upload کنید و مطمئن شوید در target Discord text channel ظاهر می‌شود.</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Discord server بسازید</span></span>
<span class="line"><span>-&gt; text channel بسازید</span></span>
<span class="line"><span>-&gt; در Discord Developer Portal یک bot بسازید</span></span>
<span class="line"><span>-&gt; Bot Token را از صفحه Bot ذخیره کنید</span></span>
<span class="line"><span>-&gt; در OAuth2 گزینه‌های bot, View Channels, Send Messages, Attach Files و Read Message History را انتخاب کنید</span></span>
<span class="line"><span>-&gt; generated URL را copy کنید و bot را برای target server authorize کنید</span></span>
<span class="line"><span>-&gt; مطمئن شوید target text channel همین permissions را دارد</span></span>
<span class="line"><span>-&gt; Developer Mode را enable کنید</span></span>
<span class="line"><span>-&gt; روی target text channel راست‌کلیک کنید و Channel ID را copy کنید</span></span>
<span class="line"><span>-&gt; Bot Token و Channel ID را در ImgBed وارد کنید</span></span>
<span class="line"><span>-&gt; Save کنید و test image upload کنید</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Discord Developers Getting Started: <a href="https://docs.discord.com/developers/quick-start/getting-started" target="_blank" rel="noreferrer">https://docs.discord.com/developers/quick-start/getting-started</a></li><li>Discord Help - Where can I find my User/Server/Message ID: <a href="https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID" target="_blank" rel="noreferrer">https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID</a></li></ol>`,37)])])}const y=i(p,[["render",b]]);export{_ as __pageData,y as default};
